import React, { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { useNavigate, useParams } from 'react-router-dom';
import { useMutation, useQuery, useQueryClient } from 'react-query';
import axios from 'axios';
import { Save, ArrowLeft } from 'lucide-react';
import ImageUpload from '../../components/ImageUpload';

const AnimalForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const isEdit = !!id;

  const [photos, setPhotos] = useState([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const { register, handleSubmit, formState: { errors }, reset, setValue } = useForm();

  // Carregar dados do animal para edição
  const { data: animal } = useQuery(
    ['animal', id],
    () => axios.get(`/api/animals/${id}`).then(res => res.data),
    { 
      enabled: isEdit,
      onSuccess: (data) => {
        // Preencher formulário
        Object.keys(data).forEach(key => {
          if (key !== 'photos') {
            setValue(key, data[key]);
          }
        });
        setPhotos(data.photos || []);
      }
    }
  );

  const mutation = useMutation(
    (data) => {
      if (isEdit) {
        return axios.put(`/api/animals/${id}`, data);
      } else {
        return axios.post('/api/animals', data);
      }
    },
    {
      onSuccess: () => {
        queryClient.invalidateQueries('animals');
        navigate('/admin/animais');
      }
    }
  );

  const handleImageUpload = async (files) => {
    const formData = new FormData();
    files.forEach(file => {
      formData.append('photos', file);
    });

    try {
      const response = await axios.post('/api/animals/upload', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });

      setPhotos(prev => [...prev, ...response.data.photos]);
    } catch (error) {
      throw new Error('Erro ao fazer upload das imagens');
    }
  };

  const handleImageRemove = async (index) => {
    const photo = photos[index];
    if (photo.path) {
      try {
        await axios.delete(`/api/animals/photo/${photo.path}`);
      } catch (error) {
        console.error('Erro ao remover imagem:', error);
      }
    }
    setPhotos(prev => prev.filter((_, i) => i !== index));
  };

  const onSubmit = async (data) => {
    setIsSubmitting(true);
    try {
      const submitData = {
        ...data,
        photos: photos
      };
      await mutation.mutateAsync(submitData);
    } catch (error) {
      alert('Erro ao salvar animal');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="mb-8">
        <button
          onClick={() => navigate('/admin/animais')}
          className="inline-flex items-center text-primary-600 hover:text-primary-700 mb-4"
        >
          <ArrowLeft className="h-4 w-4 mr-2" />
          Voltar aos Animais
        </button>
        <h1 className="text-3xl font-bold text-gray-900">
          {isEdit ? 'Editar Animal' : 'Cadastrar Novo Animal'}
        </h1>
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-8">
        {/* Informações Básicas */}
        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-semibold text-gray-900 mb-6">
            Informações Básicas
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Nome *
              </label>
              <input
                type="text"
                {...register('name', { required: 'Nome é obrigatório' })}
                className="input-field"
                placeholder="Nome do animal"
              />
              {errors.name && (
                <p className="text-red-600 text-sm mt-1">{errors.name.message}</p>
              )}
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Espécie *
              </label>
              <select
                {...register('species', { required: 'Espécie é obrigatória' })}
                className="input-field"
              >
                <option value="">Selecione a espécie</option>
                <option value="Cão">Cão</option>
                <option value="Gato">Gato</option>
                <option value="Outro">Outro</option>
              </select>
              {errors.species && (
                <p className="text-red-600 text-sm mt-1">{errors.species.message}</p>
              )}
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Idade
              </label>
              <select {...register('age')} className="input-field">
                <option value="">Selecione a idade</option>
                <option value="Filhote">Filhote (0-1 ano)</option>
                <option value="Jovem">Jovem (1-3 anos)</option>
                <option value="Adulto">Adulto (3-7 anos)</option>
                <option value="Idoso">Idoso (7+ anos)</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Porte
              </label>
              <select {...register('size')} className="input-field">
                <option value="">Selecione o porte</option>
                <option value="Pequeno">Pequeno</option>
                <option value="Médio">Médio</option>
                <option value="Grande">Grande</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Sexo
              </label>
              <select {...register('gender')} className="input-field">
                <option value="">Selecione o sexo</option>
                <option value="Macho">Macho</option>
                <option value="Fêmea">Fêmea</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Cidade *
              </label>
              <input
                type="text"
                {...register('location.city', { required: 'Cidade é obrigatória' })}
                className="input-field"
                placeholder="Cidade onde está o animal"
              />
              {errors.location?.city && (
                <p className="text-red-600 text-sm mt-1">{errors.location.city.message}</p>
              )}
            </div>
          </div>

          <div className="mt-6">
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Descrição
            </label>
            <textarea
              {...register('description')}
              rows="4"
              className="input-field"
              placeholder="Conte sobre a personalidade e características do animal..."
            />
          </div>
        </div>

        {/* Saúde */}
        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-semibold text-gray-900 mb-6">
            Informações de Saúde
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="flex items-center">
              <input
                type="checkbox"
                {...register('health.vaccinated')}
                className="h-4 w-4 text-primary-600 focus:ring-primary-500 border-gray-300 rounded"
              />
              <label className="ml-2 text-sm text-gray-700">
                Vacinado
              </label>
            </div>

            <div className="flex items-center">
              <input
                type="checkbox"
                {...register('health.neutered')}
                className="h-4 w-4 text-primary-600 focus:ring-primary-500 border-gray-300 rounded"
              />
              <label className="ml-2 text-sm text-gray-700">
                Castrado
              </label>
            </div>

            <div className="flex items-center">
              <input
                type="checkbox"
                {...register('health.dewormed')}
                className="h-4 w-4 text-primary-600 focus:ring-primary-500 border-gray-300 rounded"
              />
              <label className="ml-2 text-sm text-gray-700">
                Vermifugado
              </label>
            </div>

            <div className="flex items-center">
              <input
                type="checkbox"
                {...register('health.specialNeeds')}
                className="h-4 w-4 text-primary-600 focus:ring-primary-500 border-gray-300 rounded"
              />
              <label className="ml-2 text-sm text-gray-700">
                Necessidades Especiais
              </label>
            </div>
          </div>

          <div className="mt-6">
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Observações de Saúde
            </label>
            <textarea
              {...register('health.notes')}
              rows="3"
              className="input-field"
              placeholder="Informações adicionais sobre a saúde do animal..."
            />
          </div>
        </div>

        {/* Temperamento */}
        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-semibold text-gray-900 mb-6">
            Temperamento
          </h2>

          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
            {[
              'Calmo', 'Brincalhão', 'Carinhoso', 'Protetor', 
              'Sociável', 'Independente', 'Ativo', 'Dócil'
            ].map(trait => (
              <div key={trait} className="flex items-center">
                <input
                  type="checkbox"
                  {...register(`temperament.${trait.toLowerCase()}`)}
                  className="h-4 w-4 text-primary-600 focus:ring-primary-500 border-gray-300 rounded"
                />
                <label className="ml-2 text-sm text-gray-700">
                  {trait}
                </label>
              </div>
            ))}
          </div>
        </div>

        {/* Fotos */}
        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-semibold text-gray-900 mb-6">
            Fotos do Animal
          </h2>

          <ImageUpload
            onUpload={handleImageUpload}
            existingImages={photos}
            onRemove={handleImageRemove}
            multiple={true}
            maxFiles={10}
          />
        </div>

        {/* Botões */}
        <div className="flex justify-end space-x-4">
          <button
            type="button"
            onClick={() => navigate('/admin/animais')}
            className="btn-outline"
          >
            Cancelar
          </button>
          <button
            type="submit"
            disabled={isSubmitting}
            className="btn-primary flex items-center disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isSubmitting ? (
              <>
                <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                Salvando...
              </>
            ) : (
              <>
                <Save className="h-4 w-4 mr-2" />
                {isEdit ? 'Atualizar' : 'Cadastrar'}
              </>
            )}
          </button>
        </div>
      </form>
    </div>
  );
};

export default AnimalForm;
